import 'package:compdfkit_flutter/configuration/attributes/cpdf_editor_text_attr.dart';
import 'package:compdfkit_flutter/configuration/cpdf_configuration.dart';
import 'package:compdfkit_flutter/configuration/cpdf_options.dart';
import 'package:compdfkit_flutter/edit/cpdf_edit_manager.dart';
import 'package:compdfkit_flutter/edit/cpdf_image_data.dart';
import 'package:compdfkit_flutter/widgets/cpdf_reader_widget_controller.dart';
import 'package:compdfkit_flutter_example/widgets/cpdf_example_base.dart';
import 'package:flutter/material.dart';

class CPDFContentEditorExample extends CPDFExampleBase {
  const CPDFContentEditorExample({super.key, required super.documentPath});

  @override
  State<CPDFContentEditorExample> createState() => _CPDFContentEditorExampleState();
}

class _CPDFContentEditorExampleState extends CPDFExampleBaseState<CPDFContentEditorExample> {
  static const List<String> _menuActions = [
    'None',
    'Edit Text',
    'Edit Image',
    'Edit Path',
    'Undo',
    'Redo',
    'Insert Text',
    'Insert Image',
    'hasChanged'
  ];

  @override
  String get pageTitle => 'Content Editor Example';

  @override
  CPDFConfiguration get configuration => CPDFConfiguration(
    modeConfig: const CPDFModeConfig(
      initialViewMode: CPDFViewMode.viewer,
    ),
  );

  @override
  List<String> get menuActions => _menuActions;

  @override
  void onControllerCreated(CPDFReaderWidgetController controller) {
    super.onControllerCreated(controller);
    _setupHistoryListener(controller);
  }

  void _setupHistoryListener(CPDFReaderWidgetController controller) {
    controller.editManager.historyManager.setOnHistoryChangedListener(
          (pageIndex, canUndo, canRedo) {
        debugPrint('History changed: page=$pageIndex, canUndo=$canUndo, canRedo=$canRedo');
      },
    );
  }

  @override
  void handleMenuAction(String action, CPDFReaderWidgetController controller) async {
    switch (action) {
      case 'None':
        _changeEditType(controller, [CPDFEditType.none]);
        break;
      case 'Edit Text':
        _changeEditType(controller, [CPDFEditType.text]);
        break;
      case 'Edit Image':
        _changeEditType(controller, [CPDFEditType.image]);
        break;
      case 'Edit Path':
        _changeEditType(controller, [CPDFEditType.path]);
        break;
      case 'Undo':
        _handleUndo(controller);
        break;
      case 'Redo':
        _handleRedo(controller);
        break;
      case 'Insert Text':
        _handleInsertText(controller);
        break;
      case 'Insert Image':
        _handleInsertImage(controller);
          break;
      case 'hasChanged':
        bool hasChanged= await controller.document.hasChange();
        debugPrint('ComPDFKit-Flutter: hasChanged:$hasChanged');
        break;
    }
  }

  void _changeEditType(CPDFReaderWidgetController controller, List<CPDFEditType> types) async {
    final editManager = controller.editManager;
    final result = await editManager.changeEditType(types);
    debugPrint('Change edit type to ${types.first}: $result');
  }

  void _handleUndo(CPDFReaderWidgetController controller) async {
    final historyManager = controller.editManager.historyManager;
    final canUndo = await historyManager.canUndo();
    debugPrint('Can undo: $canUndo');

    if (canUndo) {
      await historyManager.undo();
      debugPrint('Undo executed');
    }
  }

  void _handleRedo(CPDFReaderWidgetController controller) async {
    final historyManager = controller.editManager.historyManager;
    final canRedo = await historyManager.canRedo();
    debugPrint('Can redo: $canRedo');

    if (canRedo) {
      await historyManager.redo();
      debugPrint('Redo executed');
    }
  }

  void _handleInsertText(CPDFReaderWidgetController controller) async {
    final document = controller.document;
    bool result = await document.createNewTextArea(
      pageIndex: 0,
      content: 'ComPDFKit insert text This is Test create text Area handle insert text do you know thanks you!!! hello world;',
      offset: const Offset(50, 800),
      maxWidth: 300,
      attr: const CPDFEditorTextAttr(
        fontSize: 18,
        fontColor: Colors.red,
        alignment: CPDFAlignment.left,
      ),
    );
    debugPrint('Inserted new text area :$result}');
    // await controller.reloadPages2();
  }

  void _handleInsertImage(CPDFReaderWidgetController controller) async {
    final document = controller.document;

    // base64 image data;
    var base64ImageData = CPDFImageData.fromBase64('');

    // image path data examples:
    // File file = await CPDFFileUtil.extractAsset('images/sign/signature_2.png');
    // var pathImageData = CPDFImageData.fromPath(file.path);

    // android assets folder image data example:
    // final androidAssetsImage = CPDFImageData.fromAsset('image_test.jpeg');

    // ios bundle image data example:
    // final androidAssetsImage = CPDFImageData.fromAsset('image_test.jpeg');

    // android uri image data example:
    // final uriImageData = CPDFImageData.fromUri('content://com.android.providers.downloads.documents/document/xxx.png');

    // Insert image logic here
    bool result = await document.createNewImageArea(pageIndex: 0, imageData: base64ImageData, offset: const Offset(330, 800) );
    debugPrint('ComPDFKit-Flutter: insert image :$result');
  }
}
